{
 "id": 72,
 "prompt": "Please write a literature review on the restructuring impact of Artificial Intelligence (AI) on the labor market. Focus on how AI, as a key driver of the Fourth Industrial Revolution, is causing significant disruptions and affecting various industries. Ensure the review only cites high-quality, English-language journal articles.",
 "dimension_weight": {
  "readability": 0.14,
  "insight": 0.32,
  "comprehensiveness": 0.29,
  "instruction_following": 0.25
 },
 "criterions": {
  "comprehensiveness": [
   {
    "criterion": "Grounding in AI and the Fourth Industrial Revolution (4IR) Context",
    "explanation": "Assesses whether the review adequately defines AI within the context of the 4IR and explains its fundamental role as a driver of labor market restructuring. This contextual framing is crucial for understanding the scope and nature of the impacts discussed.",
    "weight": 0.1
   },
   {
    "criterion": "Breadth of Labor Market Restructuring Dimensions Covered",
    "explanation": "Evaluates the extent to which the review addresses the multifaceted nature of AI's impact on the labor market, including job creation, job displacement, job transformation, changes in skill demands, wage effects, and productivity changes.",
    "weight": 0.25
   },
   {
    "criterion": "Scope of Industry-Specific Analysis",
    "explanation": "Checks if the review examines the restructuring impact of AI across a diverse range of relevant industries, highlighting both common trends and sector-specific nuances. The task explicitly requires focusing on 'various industries.'",
    "weight": 0.25
   },
   {
    "criterion": "Exploration of AI's Disruptive Character and Scale",
    "explanation": "Assesses whether the review sufficiently explores the 'significant disruptions' caused by AI, including the magnitude, speed, and transformative potential of these changes on labor market structures and dynamics.",
    "weight": 0.15
   },
   {
    "criterion": "Depth and Representativeness of Literature Synthesized",
    "explanation": "Evaluates if the review synthesizes a broad and representative selection of current, high-quality academic literature (from the specified journal articles), covering the main research themes, findings, and ongoing debates regarding AI's impact on the labor market. This ensures the review's content is built upon a solid and comprehensive foundation of existing knowledge.",
    "weight": 0.15
   },
   {
    "criterion": "Balanced Discussion of AI's Labor Market Impacts",
    "explanation": "Assesses whether the review presents a nuanced perspective by discussing both the challenges (e.g., displacement, skill gaps, inequality) and opportunities (e.g., new job creation, productivity gains, enhanced work quality) arising from AI's influence on the labor market.",
    "weight": 0.1
   }
  ],
  "insight": [
   {
    "criterion": "Analytical Depth in Characterizing AI-Driven Labor Market Restructuring Mechanisms",
    "explanation": "Assesses if the review moves beyond superficial descriptions of labor market changes to deeply analyze the underlying *mechanisms* (e.g., task automation, skill augmentation, job creation/destruction dynamics, organizational adaptation) through which AI specifically reshapes job roles, skill requirements, and overall labor market structures.",
    "weight": 0.25
   },
   {
    "criterion": "Critical Synthesis and Nuanced Evaluation of AI's Disruptive Impacts Across Industries",
    "explanation": "Evaluates the review's ability to critically synthesize diverse findings from high-quality journal articles to present a nuanced understanding of AI's 'significant disruptions.' This includes identifying patterns of impact, variations across different industries, and areas of consensus, debate, or uncertainty in the literature, rather than merely cataloging effects.",
    "weight": 0.25
   },
   {
    "criterion": "Insightful Integration of AI's Role within the Fourth Industrial Revolution (4IR) Context",
    "explanation": "Measures how effectively the review articulates and leverages the 4IR framework to provide a deeper, more contextualized understanding of the *nature, scale, and interconnectedness* of AI's transformative power on the labor market, rather than treating AI's impact in isolation or merely mentioning the 4IR superficially.",
    "weight": 0.15
   },
   {
    "criterion": "Identification and Articulation of Emergent Themes, Theoretical Linkages, or Novel Perspectives",
    "explanation": "Assesses whether the review transcends simple summarization to identify and clearly articulate overarching emergent themes, significant theoretical linkages between concepts, or potentially novel perspectives derived from the synthesis of the reviewed literature on AI's labor market impact.",
    "weight": 0.2
   },
   {
    "criterion": "Value and Foresight in Delineating Implications and Future Research Agendas",
    "explanation": "Evaluates the review's capacity to distill strategically valuable implications (e.g., for policy, education, workforce adaptation strategies) and to clearly delineate critical research gaps or promising future research agendas based on the comprehensive synthesis of the current state of knowledge.",
    "weight": 0.15
   }
  ],
  "instruction_following": [
   {
    "criterion": "Adherence to 'Literature Review' Format and Purpose",
    "explanation": "Assesses if the article is structured and executed as a literature review, meaning it synthesizes and discusses existing published research on the topic, rather than presenting new empirical findings or being solely an opinion piece.",
    "weight": 0.1
   },
   {
    "criterion": "Consistent Focus on 'Restructuring Impact of AI on the Labor Market'",
    "explanation": "Evaluates whether the article's content remains consistently and primarily focused on AI's restructuring effects on the labor market, as per the core task instruction, without significant digression

        if target_score_raw is not None and article_1_score_raw is None:
            article_1_score_raw = target_score_raw
            # In single scoring mode, article_2_score is not needed

        try:
            article_1_score = float(article_1_score_raw) if article_1_score_raw is not None else None
            article_2_score = float(article_2_score_raw) if article_2_score_raw is not None else None
        except (ValueError, TypeError):
            logging.warning(f"ID: {task_id} - Invalid score format for criterion '{criterion_text}' in dimension '{dim}'. Scores: art1='{article_1_score_raw}', art2='{article_2_score_raw}'. Skipping criterion.")
            continue

        # If criterion_text exists and article_1_score is not None
        if criterion_text and article_1_score is not None:
            # Check for exact match
            weight = dim_criteria_map.get(criterion_text)

            # If exact match not found, try fuzzy matching
            if weight is None:
                # First try case-insensitive matching
                criterion_lower = criterion_text.lower()
                for key, val in dim_criteria_map.items():
                    if key.lower() == criterion_lower:
                        weight = val
                        break

                # If still not found, try substring matching
                if weight is None:
                    for key, val in dim_criteria_map.items():
                        # Check if criterion text contains criteria or criteria contains criterion text
                        if criterion_lower in key.lower() or key.lower() in criterion_lower:
                            weight = val
                            break

            # If still no match found, record and use average weight
            if weight is None:
                unmatched_criteria.add(f"{dim}:{criterion_text}")
                # Calculate average weight for this dimension's criteria
                weight = sum(dim_criteria_map.values()) / len(dim_criteria_map)

            dim_target_weighted_sum += article_1_score * weight
            dim_total_weight += weight

            # Only calculate reference part if article_2_score exists
            if article_2_score is not None:
                dim_reference_weighted_sum += article_2_score * weight
        else:
            if criterion_text:
                if dim not in getattr(calculate_weighted_scores, '_warned_dims', set()):
                    logging.warning(f"ID: {task_id} - Criterion text mismatch for dimension '{dim}': '{criterion_text}'. Available criteria keys start with: {list(dim_criteria_map.keys())[:1] if dim_criteria_map else []}... Check prompt/output/criteria file consistency. Further mismatches in this dim won't be logged fully.")
                    if not hasattr(calculate_weighted_scores, '_warned_dims'): calculate_weighted_scores._warned_dims = set()
                    calculate_weighted_scores._warned_dims.add(dim)
                else:
                    logging.debug(f"ID: {task_id} - Another criterion mismatch for dimension '{dim}': '{criterion_text}'")
            elif not criterion_text:
                logging.warning(f"ID: {task_id} - Missing 'criterion' key in score item for dimension '{dim}': {score_item}. Skipping item.")

    if dim_total_weight > 0:
        dim_target_avg = dim_target_weighted_sum / dim_total_weight
        # Only calculate reference average if reference scores exist
        dim_reference_avg = dim_reference_weighted_sum / dim_total_weight if article_2_score is not None else 0
    else:
        dim_target_avg = 0
        dim_reference_avg = 0
        if len(scores_list) > 0:
            logging.warning(f"ID: {task_id} - No valid criteria scored for dimension '{dim}' despite {len(scores_list)} items in LLM output. Check for systematic mismatches. Dimension average set to 0.")

    results["target"]["dims"][f"{dim}_weighted_avg"] = dim_target_avg
    results["reference"]["dims"][f"{dim}_weighted_avg"] = dim_reference_avg

    dim_weight = dimension_weights.get(dim, 0)
    total_target_score += dim_target_avg * dim_weight
    total_reference_score += dim_reference_avg * dim_weight

# Log warning if there are unmatched criteria
if unmatched_criteria:
    logging.warning(f"ID: {task_id} - {len(unmatched_criteria)} criteria without exact matches: {unmatched_criteria}")

results["target"]["total"] = total_target_score
results["reference"]["total"] = total_reference_score

return results

